// realm backfill: island-two artist literals above already set their own
// realm ('electronic', or 'core' for brian-eno) — a.realm ?? ... only fires
// for the other ~60 region-one artists, none of which set realm themselves,
// so they all fall through to 'region-one' except the 4 core-anchor ids
// (velvet-underground, kraftwerk, can, neu) named in CORE_IDS alongside
// brian-eno. This backfills all 61 without hand-editing every literal.
const CORE_IDS = new Set(['velvet-underground', 'kraftwerk', 'can', 'neu', 'brian-eno']);

const artistsWithBios = artists.map(a => ({
  ...a,
  bio: BIOS[a.id] ?? a.bio,
  realm: a.realm ?? (CORE_IDS.has(a.id) ? 'core' : 'region-one'),
}));

